def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError(f"desalineado: {len(a)} vs {len(b)}")
    return list(zip(a, b))
try:
    zip_strict([1, 2, 3], [10, 20])
except ValueError:
    print("DESALINEADO")
try:
    zip_strict([1, 2], [3, 4])
    print("OK")
except ValueError:
    print("DESALINEADO")

def process_lines(raw_lines, max_iter=100):
    out = []
    n = 0
    for line in raw_lines:
        n += 1
        if n > max_iter:
            raise RuntimeError("guardrail: demasiadas iteraciones")
        s = line.strip()
        if not s or s == "SKIP":
            continue
        if s == "END":
            break
        out.append(s)
    return out
print(process_lines(["a", "SKIP", "b", "END", "c"]))

